  `timestamp` datetime NOT NULL,
  `target_account_id` bigint DEFAULT NULL,
  `description` varchar(255) DEFAULT NULL,
  `category` varchar(50) DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `idx_account_id` (`account_id`),
  KEY `idx_timestamp` (`timestamp`),
